'use client'

import { useRef } from 'react'
import { useId, useSignal, useSignalEffect } from '@cascivo/core'
import { builtin, t } from '@cascivo/i18n'
import styles from './alert-dialog.module.css'

export interface AlertDialogLabels {
  confirm?: string
  cancel?: string
}

export interface AlertDialogProps {
  open: boolean
  title: string
  description: string
  onConfirm: () => void
  onCancel: () => void
  labels?: AlertDialogLabels
  variant?: 'destructive' | 'default'
}

export function AlertDialog({
  open,
  title,
  description,
  onConfirm,
  onCancel,
  labels,
  variant = 'default',
}: AlertDialogProps) {
  const dialogRef = useRef<HTMLDivElement>(null)
  const titleId = useId('cascivo-alert-dialog-title')
  const descId = useId('cascivo-alert-dialog-desc')
  const isOpen = useSignal(open)
  isOpen.value = open

  const cancelRef = useRef<HTMLButtonElement>(null)
  const onCancelRef = useRef(onCancel)
  onCancelRef.current = onCancel
  const onConfirmRef = useRef(onConfirm)
  onConfirmRef.current = onConfirm

  useSignalEffect(() => {
    const el = dialogRef.current
    if (!el) return
    if (isOpen.value) {
      try {
        el.showPopover()
      } catch {
        /* noop */
      }
      requestAnimationFrame(() => cancelRef.current?.focus())
    } else {
      try {
        el.hidePopover()
      } catch {
        /* noop */
      }
    }
  })

  return (
    <div
      ref={dialogRef}
      // eslint-disable-next-line @typescript-eslint/ban-ts-comment
      // @ts-ignore — popover is a valid HTML attribute not yet in React types
      popover="manual"
      role="alertdialog"
      aria-modal="true"
      aria-labelledby={titleId}
      aria-describedby={descId}
      data-state={open ? 'open' : 'closed'}
      data-variant={variant}
      className={styles.dialog}
    >
      <div className={styles.content}>
        <p id={titleId} className={styles.title}>
          {title}
        </p>
        <p id={descId} className={styles.description}>
          {description}
        </p>
        <div className={styles.actions}>
          <button
            ref={cancelRef}
            type="button"
            className={styles.cancel}
            onClick={() => onCancelRef.current()}
          >
            {labels?.cancel ?? t(builtin.alertDialog.cancel)}
          </button>
          <button type="button" className={styles.confirm} onClick={() => onConfirmRef.current()}>
            {labels?.confirm ?? t(builtin.alertDialog.confirm)}
          </button>
        </div>
      </div>
    </div>
  )
}

@layer cascivo.component {
  .dialog {
    position: fixed;
    inset: 0;
    margin: auto;
    padding: 0;
    border: none;
    background: transparent;
    width: fit-content;
    height: fit-content;

    opacity: 1;
    scale: 1;
    transition:
      opacity var(--cascivo-motion-enter),
      scale var(--cascivo-motion-enter),
      display var(--cascivo-motion-enter) allow-discrete,
      overlay var(--cascivo-motion-enter) allow-discrete;

    @starting-style {
      opacity: 0;
      scale: 0.95;
    }

    &[data-state='closed'] {
      opacity: 0;
      scale: 0.95;
      transition:
        opacity var(--cascivo-motion-exit),
        scale var(--cascivo-motion-exit),
        display var(--cascivo-motion-exit) allow-discrete,
        overlay var(--cascivo-motion-exit) allow-discrete;
    }

    &::backdrop {
      background-color: rgb(0 0 0 / 0.5);
      backdrop-filter: blur(2px);
      opacity: 1;
      transition:
        opacity var(--cascivo-motion-enter),
        display var(--cascivo-motion-enter) allow-discrete,
        overlay var(--cascivo-motion-enter) allow-discrete;

      @starting-style {
        opacity: 0;
      }
    }

    &[data-state='closed']::backdrop {
      opacity: 0;
      transition:
        opacity var(--cascivo-motion-exit),
        display var(--cascivo-motion-exit) allow-discrete,
        overlay var(--cascivo-motion-exit) allow-discrete;
    }
  }

  .content {
    width: 28rem;
    max-width: calc(100vw - var(--cascivo-space-8));
    background: var(--cascivo-color-surface);
    border: 1px solid var(--cascivo-color-border);
    border-radius: var(--cascivo-radius-overlay);
    box-shadow: var(--cascivo-shadow-overlay);
    padding: var(--cascivo-space-6);
    display: flex;
    flex-direction: column;
    gap: var(--cascivo-space-2);
  }

  .title {
    margin: 0;
    font-size: var(--cascivo-text-lg);
    font-weight: var(--cascivo-font-semibold);
    color: var(--cascivo-color-text);
  }

  .description {
    margin: 0;
    font-size: var(--cascivo-text-sm);
    color: var(--cascivo-color-text-subtle);
  }

  .actions {
    display: flex;
    justify-content: flex-end;
    gap: var(--cascivo-space-2);
    margin-block-start: var(--cascivo-space-4);
  }

  @media (max-width: 40rem) {
    .dialog {
      /* Pin to bottom viewport edge — bottom-sheet */
      margin: 0;
      inset-block-end: 0;
      inset-inline: 0;
      max-block-size: 90dvh;
    }

    .content {
      inline-size: 100%;
      max-width: 100%;
      border-end-start-radius: 0;
      border-end-end-radius: 0;
      border-start-start-radius: var(--cascivo-radius-overlay);
      border-start-end-radius: var(--cascivo-radius-overlay);
      max-block-size: 90dvh;
      overflow-y: auto;
      /* Safe area for home indicator on iOS */
      padding-block-end: env(safe-area-inset-bottom, 0);
    }
  }

  @media (prefers-reduced-motion: reduce) {
    .dialog {
      transition: none;
    }
    .dialog[data-state='closed'] {
      transition: none;
    }
  }

  .cancel,
  .confirm {
    padding: var(--cascivo-space-2) var(--cascivo-space-4);
    border-radius: var(--cascivo-radius-control);
    font-size: var(--cascivo-text-sm);
    font-weight: var(--cascivo-font-medium);
    cursor: pointer;
    border: 1px solid transparent;
    transition:
      background-color var(--cascivo-duration-150) var(--cascivo-ease-out),
      color var(--cascivo-duration-150) var(--cascivo-ease-out);

    &:focus-visible {
      outline: none;
      box-shadow: var(--cascivo-focus-ring);
    }
  }

  .cancel {
    background: var(--cascivo-color-bg-subtle);
    color: var(--cascivo-color-text);
    border-color: var(--cascivo-color-border);

    &:hover {
      background: var(--cascivo-color-bg-muted);
    }
  }

  .confirm {
    background: var(--cascivo-color-accent);
    color: var(--cascivo-color-on-accent);

    &:hover {
      opacity: 0.9;
    }

    [data-variant='destructive'] & {
      background: var(--cascivo-color-destructive);
      color: var(--cascivo-color-on-destructive);
    }
  }
}
